"""Savitzky–Golay (собственная реализация без SciPy)."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseFilter, _check_odd_window, _reflect_paddef _savgol_smoothing_coeffs(window_length: int, polyorder: int) -> np.ndarray:    half = window_length // 2    i = np.arange(-half, half + 1, dtype=np.float64)    A = np.vander(i, N=polyorder + 1, increasing=True)    pinv_first_row = np.linalg.pinv(A)[0]    return pinv_first_row.astype(np.float64, copy=False)class SavitzkyGolayFilter(BaseFilter):    name = "Savitzky–Golay"    description = "Локальная полиномиальная аппроксимация скользящим окном."    params_schema = {        "window_length": {"type": "int", "default": 21,                          "min": 3, "max": 10_001,                          "label": "Размер окна (нечётное)"},        "polyorder":     {"type": "int", "default": 3,                          "min": 0, "max": 10,                          "label": "Порядок полинома"},    }    def _filter(self, x: np.ndarray, p: dict, signal: Signal) -> np.ndarray:        w = int(p["window_length"])        po = int(p["polyorder"])        _check_odd_window("window_length", w, x.size)        if po >= w:            raise ValueError(                f"polyorder={po} должно быть строго меньше window_length={w}"            )        coeffs = _savgol_smoothing_coeffs(w, po)        half = w // 2        padded = _reflect_pad(x, half)        return np.convolve(padded, coeffs[::-1], mode="valid")